import {
  Box,
  Button,
  FormControl,
  FormLabel,
  Input,
  Text,
} from "@chakra-ui/react";
import React, { useEffect, useState } from "react";
import AdminNavTop from "../AdminNavTop";
import { useDispatch, useSelector } from "react-redux";
import { useNavigate, useParams } from "react-router-dom";
import { patchUser } from "../../Redux/AdminReducer/action";

const EditUser = () => {
  const { id } = useParams();
  const dispatch = useDispatch();
  const navigate = useNavigate();

  const store = useSelector((store) => store.AdminReducer.users);

  const [detail, setDetail] = useState({
    name: "",
    email: "",
    password: "",
    city: "",
    age: "",
  });

  // ✅ FIX load data an toàn
  useEffect(() => {
    const user = store.find((el) => el._id === id);
    if (user) {
      setDetail(user);
    }
  }, [store, id]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setDetail((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = () => {
    dispatch(patchUser(id, detail));
    navigate("/admin/users");
  };

  return (
    <Box bg="#f7f9fa" minH="100vh" p={6}>
      <AdminNavTop />

      <Box
        maxW="600px"
        mx="auto"
        mt="80px"
        bg="white"
        p={8}
        borderRadius="lg"
        boxShadow="lg"
      >
        <Text fontSize="2xl" fontWeight="bold" mb={6}>
          Edit User
        </Text>

        <FormControl mb={4}>
          <FormLabel>Name</FormLabel>
          <Input
            name="name"
            value={detail.name}
            onChange={handleChange}
            _focus={{ borderColor: "#A435F0" }}
          />
        </FormControl>

        <FormControl mb={4}>
          <FormLabel>Email</FormLabel>
          <Input
            name="email"
            value={detail.email}
            onChange={handleChange}
            _focus={{ borderColor: "#A435F0" }}
          />
        </FormControl>

        <FormControl mb={4}>
          <FormLabel>Password</FormLabel>
          <Input
            type="password"
            name="password"
            value={detail.password}
            onChange={handleChange}
            _focus={{ borderColor: "#A435F0" }}
          />
        </FormControl>

        <FormControl mb={4}>
          <FormLabel>City</FormLabel>
          <Input
            name="city"
            value={detail.city}
            onChange={handleChange}
            _focus={{ borderColor: "#A435F0" }}
          />
        </FormControl>

        <FormControl mb={6}>
          <FormLabel>Age</FormLabel>
          <Input
            type="number"
            name="age"
            value={detail.age}
            onChange={handleChange}
            _focus={{ borderColor: "#A435F0" }}
          />
        </FormControl>

        <Button
          bg="#A435F0"
          color="white"
          w="100%"
          size="lg"
          _hover={{ bg: "#8710d8" }}
          onClick={handleSubmit}
        >
          Update User
        </Button>
      </Box>
    </Box>
  );
};

export default EditUser;
